require_once __DIR__.'/functions.php';if($_SERVER['REQUEST_METHOD']!=='POST'){http_response_code(405);exit;}verify_csrf();$viewer=require_member();$followed=filter_input(INPUT_POST,'member_id',FILTER_VALIDATE_INT);if(!$followed||(int)$viewer['id']===$followed){http_response_code(400);exit('No puedes seguir este perfil.');}$stmt=db()->prepare('SELECT profile_slug FROM members WHERE id=? AND profile_public=1 AND active=1');$stmt->execute([$followed]);$slug=$stmt->fetchColumn();if(!$slug){http_response_code(404);exit('Perfil no encontrado.');}$stmt=db()->prepare('SELECT 1 FROM member_follows WHERE follower_id=? AND followed_id=?');$stmt->execute([$viewer['id'],$followed]);if($stmt->fetchColumn()){db()->prepare('DELETE FROM member_follows WHERE follower_id=? AND followed_id=?')->execute([$viewer['id'],$followed]);}else{db()->prepare('INSERT INTO member_follows(follower_id,followed_id) VALUES(?,?)')->execute([$viewer['id'],$followed]);}redirect('/usuario/'.rawurlencode((string)$slug));
